function wordSubsets(words1, words2) {
    const maxChars = {};
    for (const word of words2) {
        const chars = {};
        for (const c of word) {
            chars[c] = (chars[c] || 0) + 1;
        }
        for (const c in chars) {
            maxChars[c] = Math.max(maxChars[c] || 0, chars[c]);
        }
    }

    const result = [];
    for (const word of words1) {
        const wordChars = {};
        for (const c of word) {
            wordChars[c] = (wordChars[c] || 0) + 1;
        }

        let universal = true;
        for (const c in maxChars) {
            if ((wordChars[c] || 0) < maxChars[c]) {
                universal = false;
                break;
            }
        }

        if (universal) {
            result.push(word);
        }
    }

    return result;
}
```


    1. Create a hashmap that contains the maximum frequency of each character across all words in `words2`. We will call this hashmap `max_chars`.
2. Iterate through every word in `words1` and for each word, create another hashmap `word_chars` that counts the frequency of each character in that word.
3. Check if every character in `max_chars` is present in `word_chars` with a frequency equal to or greater than its frequency in `max_chars`. If this is true for every character, the word is considered universal and we add it to the list of results.
4. Return the list of results.

